import{_ as e,o as t,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"5.7 小结","description":"","frontmatter":{},"headers":[],"relativePath":"05/7.md","filePath":"05/7.md","lastUpdated":null}'),o={name:"05/7.md"};function s(i,a,n,_,d,c){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="_5-7-小结" tabindex="-1">5.7 小结 <a class="header-anchor" href="#_5-7-小结" aria-label="Permalink to &quot;5.7 小结&quot;">​</a></h1><p>这一章我们讲解了Go如何设计database/sql接口，然后介绍了各种第三方关系型数据库驱动的使用。接着介绍了beedb，一种基于关系型数据库的ORM库，如何对数据库进行简单的操作。最后介绍了NOSQL的一些知识，目前Go对于NOSQL支持还是不错，因为Go作为21世纪的C语言，那么对于21世纪的数据库也是支持的相当好。</p><p>通过这一章的学习，我们学会了如何操作各种数据库，那么就解决了我们数据存储的问题，这是Web里面最重要的一部分，所以希望大家能够深入的去了解database/sql的设计思想。</p><blockquote><p><a href="http://go-database-sql.org/" target="_blank" rel="noreferrer">Go database/sql tutorial</a> 里提供了惯用的范例及详细的说明。</p></blockquote><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一节: <a href="/05/6.html">NOSQL数据库操作</a></li><li>下一章: <a href="/06/0.html">session和数据存储</a></li></ul>',6)])])}const f=e(o,[["render",s]]);export{p as __pageData,f as default};
